const L = require('fs').readFileSync(0, 'utf8').split('\n');
const n = Number(L[0]);
const arr = L[1].trim().split(/\s+/).map(Number);
const avg = Math.floor(arr.reduce((a, b) => a + b, 0) / n);
let g;
if (avg >= 90) g = "A";
else if (avg >= 70) g = "B";
else if (avg >= 50) g = "C";
else g = "D";
console.log(avg + "\n" + g);
